-- Ken's Hardened V2 Fix

local b64_0xIIll11 = {}
local char_0xlIlIlI='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xI1Illl=1,#char_0xlIlIlI do b64_0xIIll11[char_0xlIlIlI:sub(i_0xI1Illl,i_0xI1Illl)] = i_0xI1Illl - 1 end

function b64_0xIIll11.dec_0xIllll1(d_0xl1I111)
    d_0xl1I111 = string.gsub(d_0xl1I111, '[^'..char_0xlIlIlI..'=]', '')
    local r_0xIl11ll = {}
    for i_0xI1Illl=1, #d_0xl1I111, 4 do
        local c_0xII1l1l = b64_0xIIll11[d_0xl1I111:sub(i_0xI1Illl,i_0xI1Illl)] or 0
        local c_0x1IlIIl = b64_0xIIll11[d_0xl1I111:sub(i_0xI1Illl+1,i_0xI1Illl+1)] or 0
        local c_0x1IlIlI, c_0xlI1I1I = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xl1I111:sub(i_0xI1Illl+2,i_0xI1Illl+2)
        if ch3 == "=" then has3 = false else c_0x1IlIlI = b64_0xIIll11[ch3] or 0 end
        local ch4 = d_0xl1I111:sub(i_0xI1Illl+3,i_0xI1Illl+3)
        if ch4 == "=" then has4 = false else c_0xlI1I1I = b64_0xIIll11[ch4] or 0 end
        local b_0x1lI1I1 = c_0xII1l1l * (2^18) + c_0x1IlIIl * (2^12) + c_0x1IlIlI * (2^6) + c_0xlI1I1I
        local b_0xlIlIlI = math.floor(b_0x1lI1I1 / (2^16)) % (2^8)
        local b_0xI1IlII = math.floor(b_0x1lI1I1 / (2^8)) % (2^8)
        local b_0xIlI1II = b_0x1lI1I1 % (2^8)
        table.insert(r_0xIl11ll, string.char(b_0xlIlIlI))
        if has3 then table.insert(r_0xIl11ll, string.char(b_0xI1IlII)) end
        if has4 then table.insert(r_0xIl11ll, string.char(b_0xIlI1II)) end
    end
    return table.concat(r_0xIl11ll)
end


local function bxor_0xIIIII1(a_0xIll11I,b_0x1IIlI1)
    if bit32 then return bit32.bxor(a_0xIll11I,b_0x1IIlI1) end
    local r_0xlIllIl = 0
    for i_0xl1lIIl = 0, 7 do
        local x_0xlIIIll = a_0xIll11I % 2
        local y_0xIIlIl1 = b_0x1IIlI1 % 2
        if x_0xlIIIll ~= y_0xIIlIl1 then r_0xlIllIl = r_0xlIllIl + (2^i_0xl1lIIl) end
        a_0xIll11I = math.floor(a_0xIll11I / 2)
        b_0x1IIlI1 = math.floor(b_0x1IIlI1 / 2)
    end
    return r_0xlIllIl
end


local function bxor_str_0xIl111I(s_0xl1IIl1, k_0xl1lllI)
    local r_0xll1ll1 = {}
    for i_0x1l1II1=1, #s_0xl1IIl1 do
        local b_0xIIIllI = string.byte(s_0xl1IIl1, i_0x1l1II1)
        local kb_0xIII1l1 = string.byte(k_0xl1lllI, (i_0x1l1II1-1) % #k_0xl1lllI + 1)
        r_0xll1ll1[i_0x1l1II1] = string.char(bxor_0xIIIII1(b_0xIIIllI, kb_0xIII1l1))
    end
    return table.concat(r_0xll1ll1)
end


local function getkeys_0xI11IlI()
    local seed = b64_0xIIll11.dec_0xIllll1("QlJRZzRpRmY=")
    local k1_enc = b64_0xIIll11.dec_0xIllll1("Mz0IKGwzKSk=")
    local k2_enc = b64_0xIIll11.dec_0xIllll1("EyI9HWAbLxQ=")
    return bxor_str_0xIl111I(k1_enc, seed), bxor_str_0xIl111I(k2_enc, seed)
end


local function cff_0x1IIlIl(a_0xIIlIlI)
    local st_0xIIllll = 0
    local res_0xl1I11I = a_0xIIlIlI
    while true do
        if st_0xIIllll == 0 then
            res_0xl1I11I = res_0xl1I11I + 1
            st_0xIIllll = 1
        elseif st_0xIIllll == 1 then
            res_0xl1I11I = res_0xl1I11I * 2
            st_0xIIllll = 2
        elseif st_0xIIllll == 2 then
            res_0xl1I11I = res_0xl1I11I - 3
            st_0xIIllll = 3
        else
            break
        end
    end
    return res_0xl1I11I
end


local function chain_0xIl1IlI(x) return x*2 end
local function chain_0xlIlII1(x) return chain_0xIl1IlI(x)+1 end


local d_0xllII11 = {
  {op=255, val="", is_enc=true},
}
local pc_0xIl1lIl = 1
local stk_0xlIIIlI = {}
stk_0xlIIIlI._jmp = nil


local disp_0xI11lII = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xI11IlI()

local state_0xIlIl1I = 0
while true do
    if state_0xIlIl1I == 0 then  -- FETCH
        if pc_0xIl1lIl > #d_0xllII11 then break end
        local inst = d_0xllII11[pc_0xIl1lIl]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIIll11.dec_0xIllll1(val)
            d = bxor_str_0xIl111I(d, k2)
            val = bxor_str_0xIl111I(d, k1)
        end
        stk_0xlIIIlI._jmp = nil
        pc_0xIl1lIl = pc_0xIl1lIl + 1
        cur_op_0xI1IIl1 = opcode
        cur_val_0xlIl1lI = val
        state_0xIlIl1I = 1

    elseif state_0xIlIl1I == 1 then  -- EXECUTE
        local handler = disp_0xI11lII[cur_op_0xI1IIl1]
        if handler then
            handler(stk_0xlIIIlI, cur_val_0xlIl1lI)
        end
        if stk_0xlIIIlI._jmp then
            pc_0xIl1lIl = pc_0xIl1lIl + stk_0xlIIIlI._jmp
        end
        state_0xIlIl1I = 0
